n// PRODUCT\n//////////////////////////////////////////////////////\n\nmodel Product {\n  id String @id @default(uuid())\n\n  title       String\n  description String\n\n  slug String @unique\n\n  brand String?\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id])\n\n  variants ProductVariant[]\n\n  images ProductImage[]\n\n  reviews Review[]\n\n  createdAt DateTime   @default(now())\n  updatedAt DateTime   @updatedAt\n  wishlists Wishlist[]\n}\n\n//////////////////////////////////////////////////////\n// PRODUCT VARIANTS (SIZE/COLOR)\n//////////////////////////////////////////////////////\n\nmodel ProductVariant {\n  id String @id @default(uuid())\n\n  productId String\n  product   Product @relation(fields: [productId], references: [id])\n\n  sku String @unique\n\n  price Float\n  stock Int\n\n  size  String?\n  color String?\n\n  cartItems  CartItem[]\n  orderItems OrderItem[]\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// PRODUCT IMAGES\n//////////////////////////////////////////////////////\n\nmodel ProductImage {\n  id String @id @default(uuid())\n\n  productId String\n  product   Product @relation(fields: [productId], references: [id])\n\n  url String\n}\n\n//////////////////////////////////////////////////////\n// REVIEW\n//////////////////////////////////////////////////////\n\nmodel Review {\n  id String @id @default(uuid())\n\n  rating  Int\n  comment String?\n\n  userId    String\n  productId String\n\n  user    User    @relation(fields: [userId], references: [id])\n  product Product @relation(fields: [productId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// WISHLIST\n//////////////////////////////////////////////////////\n\nmodel Wishlist {\n  id String @id @default(uuid())\n\n  userId    String\n  productId String\n\n  user    User    @relation(fields: [userId], references: [id])\n  product Product @relation(fields: [productId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// CART\n//////////////////////////////////////////////////////\n\nmodel Cart {\n  id String @id @default(uuid())\n\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id])\n\n  items CartItem[]\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// CART ITEM\n//////////////////////////////////////////////////////\n\nmodel CartItem {\n  id String @id @default(uuid())\n\n  cartId    String\n  variantId String\n\n  quantity Int\n\n  cart    Cart           @relation(fields: [cartId], references: [id])\n  variant ProductVariant @relation(fields: [variantId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// ORDER\n//////////////////////////////////////////////////////\n\nmodel Order {\n  id String @id @default(uuid())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  addressId String\n  address   Address @relation(fields: [addressId], references: [id])\n\n  status OrderStatus @default(PENDING)\n\n  totalAmount Float\n\n  couponId String?\n  coupon   Coupon? @relation(fields: [couponId], references: [id])\n\n  items OrderItem[]\n\n  payment Payment?\n\n  tracking OrderTracking?\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// ORDER ITEMS\n//////////////////////////////////////////////////////\n\nmodel OrderItem {\n  id String @id @default(uuid())\n\n  orderId   String\n  variantId String\n\n  quantity Int\n  price    Float\n\n  order   Order          @relation(fields: [orderId], references: [id])\n  variant ProductVariant @relation(fields: [variantId], references: [id])\n}\n\n//////////////////////////////////////////////////////\n// ORDER TRACKING\n//////////////////////////////////////////////////////\n\nmodel OrderTracking {\n  id String @id @default(uuid())\n\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n\n  carrier    String?\n  trackingId String?\n\n  shippedAt   DateTime?\n  deliveredAt DateTime?\n}\n\n//////////////////////////////////////////////////////\n// PAYMENT\n//////////////////////////////////////////////////////\n\nmodel Payment {\n  id String @id @default(uuid())\n\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n\n  provider PaymentProvider\n\n  transactionId String?\n\n  amount Float\n\n  status PaymentStatus @default(PENDING)\n\n  createdAt DateTime @default(now())\n}\n\n//////////////////////////////////////////////////////\n// COUPONS\n//////////////////////////////////////////////////////\n\nmodel Coupon {\n  id String @id @default(uuid())\n\n  code     String @unique\n  discount Float\n\n  expiresAt DateTime?\n\n  orders Order[]\n}\n\n//////////////////////////////////////////////////////\n// OTP\n//////////////////////////////////////////////////////\n\nmodel OTP {\n  id String @id @default(uuid())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  code String\n\n  expiresAt DateTime\n\n  createdAt DateTime @default(now())\n}\n",
